import React, { useState } from 'react'
import Taskcard from './Taskcard'

const Tasks = () => {
  const [taskName, settaskName] = useState('')
  const [tasks, setTasks] = useState([])

  // function handleAdd() {
  //   if (!taskName.trim()) return;
  //   const newtask = {
  //     id: crypto.randomUUID(),
  //     title: taskName.trim(),
  //   };
  //   setTasks(prev => [...prev, newtask]);
  //   settaskName('');
  // }

  // function handleDeleteTask(id) {
  //   setTasks(prev => prev.filter(task => task.id !== id));
  // }
function handleDeleteTask(id) {
  setTasks(prev => {
    const updatedTasks = prev.filter(task => task.id !== id);
    localStorage.setItem('mainTasks', JSON.stringify(updatedTasks)); // ✅ Save
    return updatedTasks;
  });
}

function handleAdd() {
  if (!taskName.trim()) return;

  const newtask = {
    id: crypto.randomUUID(),
    title: taskName.trim(),
  };

  setTasks(prev => {
    const updatedTasks = [...prev, newtask];
    localStorage.setItem('mainTasks', JSON.stringify(updatedTasks)); // ✅ Save
    return updatedTasks;
  });

  settaskName('');
}


  return (
    <div className='task-page'>
      <h1 className="tasks-heading">Tasks</h1>

      <div className='task-header'>
        <div>
          <input className='task-name' placeholder='Enter Task title...' value={taskName} onChange={(e) => settaskName(e.target.value)} />
        </div>
        <div>
          <button className='task-add' onClick={handleAdd}>Add</button>
        </div>
      </div>

      <div className='tasks-list'>
        {tasks.map((task) => (
          <Taskcard task={task} key={task.id} handleDeleteTask={handleDeleteTask} />
        ))}
      </div>

      <style>{`
        .tasks-heading {
          font-size: 2.5rem;
          text-align: center;
          margin-bottom: 1.5rem;
        }

        .task-page {
          padding: 1rem;
          font-family: 'Cedarville Cursive', cursive;
          max-width: 1200px;
          margin: auto;
        }

        .task-header {
          display: flex;
          flex-direction: row;
          align-items: center;
          justify-content: center;
          gap: 1rem;
          flex-wrap: wrap;
          margin-bottom: 2rem;
        }

        .task-name {
          background-color: var(--secondary-color);
          border: none;
          padding: 10px 15px;
          min-width: 250px;
          border-radius: 5px;
          font-size: 1.2rem;
          font-family: 'Cedarville Cursive', cursive;
          color: var(--text);
          flex: 1 1 250px;
        }

        .task-add {
          background-color: var(--button-color);
          border: none;
          padding: 10px 15px;
          min-width: 100px;
          border-radius: 5px;
          font-size: 1.2rem;
          color: var(--bg-parchment);
          font-family: 'Cedarville Cursive', cursive;
          flex-shrink: 0;
        }

        .task-name::placeholder {
          color: var(--text);
          opacity: 1;
        }

        .tasks-list {
          display: flex;
          flex-wrap: wrap;
          justify-content: center;
          align-items: flex-start; /* key change: let cards grow independently */
          gap: 1rem;
          padding: 0 1rem;
        }

        @media (max-width: 768px) {
          .task-header {
            flex-direction: column;
            align-items: stretch;
            gap: 0.8rem;
          }

          .task-name,
          .task-add {
            width: 90%;
            font-size: 1rem;
          }

          .tasks-heading {
            font-size: 2rem;
          }
        }

        @media (max-width: 480px) {
          .task-page {
            padding: 0.5rem;
          }

          .tasks-heading {
            font-size: 1.5rem;
          }

          .task-name,
          .task-add {
            font-size: 0.95rem;
          }
        }
      `}</style>
    </div>
  )
}

export default Tasks
